sql.where:
u.deleted = 0

    AND (
        u.username LIKE CONCAT('%', #{keyword}, '%')
        OR u.name LIKE CONCAT('%', #{keyword}, '%')
        OR u.email LIKE CONCAT('%', #{keyword}, '%')
    )


    AND u.role_id = #{roleId}


    AND u.status = #{status}

mapper.select:
SELECT EXISTS(
    SELECT 1 FROM user
    WHERE username = #{username}
      AND deleted = 0
)

SELECT EXISTS(
    SELECT 1 FROM user
    WHERE email = #{email}
      AND deleted = 0
)
